   221	        private void serializeKeyValuePairs(ObjectNode node, Shape shape) {
   222	            if (node.isEmpty()) {
   223	                return;
   224	            }
   225	
   226	            // If we're looking at a structure or union shape, we'll need to get the member shape based on the
   227	            // node key. Here we pre-compute a mapping, so we don't have to traverse the member list every time.
   228	            Map<String, MemberShape> members;
   229	            if (shape == null) {
