        private static final Map<ShapeType, Integer> PRIORITY = MapUtils.of(
                ShapeType.SERVICE,
                0,
                ShapeType.RESOURCE,
                1,
                ShapeType.OPERATION,
                2,
                ShapeType.STRUCTURE,
                3,
                ShapeType.UNION,
                4,
                ShapeType.LIST,
                5,
                ShapeType.SET,
                6,
                ShapeType.MAP,
                7);

        @Override
        public int compare(Shape s1, Shape s2) {
